/**
 * i18n - Internationalization Support
 * タスク4.2: ブラウザ言語検知と多言語対応
 */

export type SupportedLocale = 'ja' | 'en' | 'zh' | 'ko';

export interface I18nMessages {
  placeholder: string;
  send: string;
  loading: string;
  error: string;
  retry: string;
  charLimitError: string;
  piiError: string;
  welcome: string;
}

const messages: Record<SupportedLocale, I18nMessages> = {
  ja: {
    placeholder: 'メッセージを入力してください',
    send: '送信',
    loading: '応答を生成中...',
    error: 'エラーが発生しました',
    retry: '再試行',
    charLimitError: '256文字以内で入力してください',
    piiError: '個人情報は入力しないでください',
    welcome:
      'こんにちは！ワールドマスターズゲームズ2027関西のサポートチャットです 🎉\n大会に関するご質問にAIがお答えします。\nメッセージを入力してください。',
  },
  en: {
    placeholder: 'Enter your message',
    send: 'Send',
    loading: 'Generating response...',
    error: 'An error occurred',
    retry: 'Retry',
    charLimitError: 'Please enter within 256 characters',
    piiError: 'Please do not enter personal information',
    welcome:
      'Hello! Welcome to World Masters Games 2027 Kansai Support Chat 🎉\nOur AI will answer your questions about the games.\nPlease enter your message.',
  },
  zh: {
    placeholder: '请输入消息',
    send: '发送',
    loading: '正在生成回复...',
    error: '发生错误',
    retry: '重试',
    charLimitError: '请在256个字符以内输入',
    piiError: '请勿输入个人信息',
    welcome:
      '您好！欢迎使用2027年世界大师运动会关西支持聊天 🎉\nAI将回答您关于大会的问题。\n请输入您的消息。',
  },
  ko: {
    placeholder: '메시지를 입력하세요',
    send: '전송',
    loading: '응답 생성 중...',
    error: '오류가 발생했습니다',
    retry: '재시도',
    charLimitError: '256자 이내로 입력해주세요',
    piiError: '개인정보를 입력하지 마세요',
    welcome:
      '안녕하세요! 2027 월드마스터즈게임 간사이 지원 챗봇입니다 🎉\nAI가 대회에 관한 질문에 답변해 드립니다.\n메시지를 입력해 주세요.',
  },
};

/**
 * ブラウザ言語を検知してサポート対象のロケールを返す
 */
export function detectBrowserLocale(): SupportedLocale {
  if (typeof window === 'undefined') {
    return 'ja'; // SSR時はデフォルト
  }

  const browserLang = navigator.language.toLowerCase();

  if (browserLang.startsWith('ja')) return 'ja';
  if (browserLang.startsWith('en')) return 'en';
  if (browserLang.startsWith('zh')) return 'zh';
  if (browserLang.startsWith('ko')) return 'ko';

  return 'ja'; // デフォルトは日本語
}

/**
 * ロケールに対応するメッセージを取得
 */
export function getMessages(locale: SupportedLocale): I18nMessages {
  return messages[locale];
}

