'use client';

/**
 * useChatUI Hook
 * ChatWindow と ChatWidgetFrame で共通するチャットロジックを抽出
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { useChat, type UseChatOptions } from 'ai/react';
import { detectBrowserLocale, getMessages, type SupportedLocale } from '@/client/lib/theme/i18n';

export interface UseChatUIOptions {
  onError?: UseChatOptions['onError'];
}

export function useChatUI(options: UseChatUIOptions = {}) {
  const [locale, setLocale] = useState<SupportedLocale>('ja');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Detect browser locale on mount
  useEffect(() => {
    const detectedLocale = detectBrowserLocale();
    setLocale(detectedLocale);
  }, []);

  const messages_i18n = getMessages(locale);

  const chatResult = useChat({
    api: '/api/chat',
    body: { locale },
    onError: options.onError,
  });

  const { messages, input, setInput, handleSubmit, isLoading } = chatResult;

  // Auto scroll on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  // Input change handler
  const handleInputChange = useCallback(
    (value: string) => {
      setInput(value);
    },
    [setInput]
  );

  // Form submit handler
  const handleFormSubmit = useCallback(() => {
    if (input.trim()) {
      const syntheticEvent = {
        preventDefault: () => {},
      } as React.FormEvent<HTMLFormElement>;
      handleSubmit(syntheticEvent);
    }
  }, [input, handleSubmit]);

  return {
    // Locale
    locale,
    messages_i18n,

    // Refs
    messagesEndRef,

    // Chat state (from useChat)
    messages: chatResult.messages,
    input: chatResult.input,
    isLoading: chatResult.isLoading,
    error: chatResult.error,
    reload: chatResult.reload,

    // Handlers
    handleInputChange,
    handleFormSubmit,
  };
}

